mapper.insert:
insert into public_item (
                          cmn_facility_item_no
                        , cmn_facility_no
                        , item_nm
                        , cmn_facility_stts_cd
) values (
           'ITEM' || lpad(seq_public_item.nextval, 4, '0')
         , #{cmnFacilityNo}
         , #{itemNm}
         , nvl(#{cmnFacilitySttsCd}, 'OPEN')
         )

mapper.update:
update public_item
set
    item_nm              = #{itemNm}
  , cmn_facility_stts_cd = #{cmnFacilitySttsCd}
where cmn_facility_item_no = #{cmnFacilityItemNo}

mapper.select:
select pi.cmn_facility_item_no , pi.cmn_facility_no , pi.item_nm , pi.cmn_facility_stts_cd , pf.cmn_facility_nm from public_item pi inner join public_facility pf on pf.cmn_facility_no = pi.cmn_facility_no inner join facility f on f.facility_no = pf.facility_no inner join mgmt_office mo on mo.apt_cmplex_no = f.apt_cmplex_no where mo.mgmt_ofc_no = #{mgmtOfcNo}
and pi.cmn_facility_item_no like 'ITEM' || #{itemNo} || '%'
and pi.cmn_facility_no like 'CMN' || #{facilityNo} || '%'
and pi.item_nm like '%' || #{itemNm} || '%'
and pi.cmn_facility_stts_cd = #{sttsCd}
order by pi.cmn_facility_item_no desc offset (#{page} - 1) * #{pageSize} rows fetch next #{pageSize} rows only

select count(*) from public_item pi inner join public_facility pf on pf.cmn_facility_no = pi.cmn_facility_no inner join facility f on f.facility_no = pf.facility_no inner join mgmt_office mo on mo.apt_cmplex_no = f.apt_cmplex_no where mo.mgmt_ofc_no = #{mgmtOfcNo}
and pi.cmn_facility_item_no like 'ITEM' || #{itemNo} || '%'
and pi.cmn_facility_no like 'CMN' || #{facilityNo} || '%'
and pi.item_nm like '%' || #{itemNm} || '%'
and pi.cmn_facility_stts_cd = #{sttsCd}
